              }
            } else if (target.id === 'icon') {
              if (dialog.open) {
                dialog.close();
              } else {
                dialog.className = getPositionClasses(target);
                dialog.show();
              }
            } else if (target.id === 'loc' && target.dataset.url) {
              globalThis.qwikOpenInEditor(target.dataset.url);
            }
          }
